import React from 'react';
import './Offer.css';

const services = [
  {
    id: 1,
    tag: 'Office of multiple interest content',
    title: 'Collaborative & partnership',
  },
  {
    id: 2,
    tag: 'The hanger US Air force digital experimental',
    title: 'We talk about our weight',
  },
  {
    id: 3,
    tag: 'Delta faucet content, racial, digital',
    title: 'Piloting digital confidence',
  },
];

const Offer = () => {
  return (
    <section className="offer">
      {/* Decorative blob */}
      <div className="offer__blob" />

      {/* Header: avatar stack + V badge + number */}
      <div className="offer__header">
        <div className="offer__avatar-stack">
          <div className="offer__av" style={{ background: '#f4a261' }}>
            <img src="https://randomuser.me/api/portraits/women/44.jpg" alt="v" />
          </div>
          <div className="offer__av offer__av--badge">V</div>
        </div>
        <span className="offer__count">3</span>
        <div className="offer__rubul-badge">rubul</div>
      </div>

      <h2 className="offer__title">
        What we can<br />
        <span className="offer__title--ul">offer</span> you!
      </h2>

      <div className="offer__list">
        {services.map((svc) => (
          <div key={svc.id} className="offer__item">
            <div className="offer__item-tag">{svc.tag}</div>
            <div className="offer__item-title">{svc.title}</div>
            <div className="offer__item-arrow">→</div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Offer;
